package com.enterprise.auth.service;

import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AccountLockedException;
import org.springframework.stereotype.Service;

@Service
public class RateLimitService {

    private static final int MAX_BACKUP_CODE_ATTEMPTS = 5;
    private static final int MAX_MFA_ATTEMPTS = 5;
    private static final int LOCKOUT_WINDOW_MINUTES = 15;

    private final AuditService auditService;

    public RateLimitService(AuditService auditService) {
        this.auditService = auditService;
    }

    public void checkBackupCodeRateLimit(User user) {
        long failedAttempts = auditService.countRecentFailedAttempts(
                user, "BACKUP_CODE_VERIFICATION", LOCKOUT_WINDOW_MINUTES);
        if (failedAttempts >= MAX_BACKUP_CODE_ATTEMPTS) {
            throw new AccountLockedException(
                    "Too many failed backup code attempts. Account temporarily locked for " + LOCKOUT_WINDOW_MINUTES + " minutes.");
        }
    }

    public void checkMfaRateLimit(User user) {
        long failedAttempts = auditService.countRecentFailedAttempts(
                user, "MFA_VERIFICATION", LOCKOUT_WINDOW_MINUTES);
        if (failedAttempts >= MAX_MFA_ATTEMPTS) {
            throw new AccountLockedException(
                    "Too many failed MFA attempts. Account temporarily locked for " + LOCKOUT_WINDOW_MINUTES + " minutes.");
        }
    }
}

