import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;

@Service
public class TotpService {

    private static final int TIME_STEP = 30;
    private static final int CODE_DIGITS = 6;
    private static final String HMAC_ALGORITHM = "HmacSHA1";
    private static final int SECRET_LENGTH = 20;

    private final SecureRandom secureRandom = new SecureRandom();

    public String generateSecret() {
        byte[] secretBytes = new byte[SECRET_LENGTH];
        secureRandom.nextBytes(secretBytes);
        return base32Encode(secretBytes);
    }

    public boolean verifyCode(String secret, String code) {
        if (secret == null || code == null || code.length() != CODE_DIGITS) {
            return false;
        }

        try {
            long currentTimeStep = Instant.now().getEpochSecond() / TIME_STEP;
            // Allow 1 time step window in each direction for clock skew
            for (int i = -1; i <= 1; i++) {
                String generatedCode = generateCode(secret, currentTimeStep + i);
                if (constantTimeEquals(generatedCode, code)) {
                    return true;
                }
            }
        } catch (Exception e) {
            return false;
        }
        return false;
    }

    public String getQrCodeUri(String secret, String username, String issuer) {
        return String.format("otpauth://totp/%s:%s?secret=%s&issuer=%s&algorithm=SHA1&digits=%d&period=%d",
                issuer, username, secret, issuer, CODE_DIGITS, TIME_STEP);
    }

    private String generateCode(String secret, long timeStep) throws Exception {
        byte[] secretBytes = base32Decode(secret);
        byte[] timeBytes = ByteBuffer.allocate(8).putLong(timeStep).array();

        Mac mac = Mac.getInstance(HMAC_ALGORITHM);
        mac.init(new SecretKeySpec(secretBytes, HMAC_ALGORITHM));
        byte[] hash = mac.doFinal(timeBytes);

        int offset = hash[hash.length - 1] & 0x0F;
        int truncatedHash = ((hash[offset] & 0x7F) << 24)
                | ((hash[offset + 1] & 0xFF) << 16)
                | ((hash[offset + 2] & 0xFF) << 8)
                | (hash[offset + 3] & 0xFF);

        int code = truncatedHash % (int) Math.pow(10, CODE_DIGITS);
        return String.format("%0" + CODE_DIGITS + "d", code);
    }

    private boolean constantTimeEquals(String a, String b) {
        if (a.length() != b.length()) return false;
        int result = 0;
        for (int i = 0; i < a.length(); i++) {
            result |= a.charAt(i) ^ b.charAt(i);
        }
        return result == 0;
    }

    private static final String BASE32_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

    private String base32Encode(byte[] data) {
        StringBuilder result = new StringBuilder();
        int buffer = 0;
        int bitsLeft = 0;
        for (byte b : data) {
            buffer = (buffer << 8) | (b & 0xFF);
            bitsLeft += 8;
            while (bitsLeft >= 5) {
                result.append(BASE32_CHARS.charAt((buffer >> (bitsLeft - 5)) & 0x1F));
                bitsLeft -= 5;
            }
        }
        if (bitsLeft > 0) {
            result.append(BASE32_CHARS.charAt((buffer << (5 - bitsLeft)) & 0x1F));
        }
        return result.toString();
    }

    private byte[] base32Decode(String encoded) {
        encoded = encoded.toUpperCase().replaceAll("[^A-Z2-7]", "");
        int buffer = 0;
        int bitsLeft = 0;
        byte[] result = new byte[encoded.length() * 5 / 8];
        int index = 0;
        for (char c : encoded.toCharArray()) {
            int val = BASE32_CHARS.indexOf(c);
            if (val < 0) continue;
            buffer = (buffer << 5) | val;
            bitsLeft += 5;
            if (bitsLeft >= 8) {
                result[index++] = (byte) (buffer >> (bitsLeft - 8));
                bitsLeft -= 8;
            }
        }
        return result;
    }
}

// ==================== Service: BackupCodeService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.dto.BackupCodeStatusResponse;
import com.enterprise.auth.entity.BackupCode;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.AccountLockedException;
import com.enterprise.auth.exception.InvalidBackupCodeException;
import com.enterprise.auth.repository.BackupCodeRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;

@Service
public class BackupCodeService {

    private static final Logger logger = LoggerFactory.getLogger(BackupCodeService.class);
    private static final int BACKUP_CODE_EXPIRY_DAYS = 365;

    private final BackupCodeRepository backupCodeRepository;
    private final BackupCodeGenerator backupCodeGenerator;
    private final PasswordEncoder passwordEncoder;
    private final AuditService auditService;
    private final RateLimitService rateLimitService;

    public BackupCodeService(BackupCodeRepository backupCodeRepository,
                             BackupCodeGenerator backupCodeGenerator,
                             PasswordEncoder passwordEncoder,
                             AuditService auditService,
                             RateLimitService rateLimitService) {
        this.backupCodeRepository = backupCodeRepository;
        this.backupCodeGenerator = backupCodeGenerator;
        this.passwordEncoder = passwordEncoder;
        this.auditService = auditService;
        this.rateLimitService = rateLimitService;
    }

    @Transactional
    public List<String> generateBackupCodes(User user) {
        // Invalidate existing codes
        backupCodeRepository.deleteAllByUser(user);

        List<String> plainCodes = backupCodeGenerator.generatePlainCodes();
        LocalDateTime expiresAt = LocalDateTime.now().plusDays(BACKUP_CODE_EXPIRY_DAYS);

        for (String plainCode : plainCodes) {
            String normalizedCode = backupCodeGenerator.normalizeCode(plainCode);
            String hashedCode = passwordEncoder.encode(normalizedCode);
            BackupCode backupCode = new BackupCode(hashedCode, user, expiresAt);
            backupCodeRepository.save(backupCode);
        }

        auditService.logAction(user, "BACKUP_CODES_GENERATED", true,
                "Generated " + plainCodes.size() + " new backup codes", null);

        logger.info("Generated {} backup codes for user: {}", plainCodes.size(), user.getUsername());

        return plainCodes;
    }

    @Transactional
    public boolean verifyBackupCode(User user, String providedCode, String ipAddress) {
        // Check rate limiting
        rateLimitService.checkBackupCodeRateLimit(user);

        String normalizedCode = backupCodeGenerator.normalizeCode(providedCode);

        List<BackupCode> validCodes = backupCodeRepository.findValidCodesByUser(user);

        if (validCodes.isEmpty()) {
            auditService.logAction(user, "BACKUP_CODE_VERIFICATION", false,
                    "No valid backup codes available", ipAddress);
            throw new InvalidBackupCodeException("No valid backup codes available. Please contact support.");
        }

        for (BackupCode backupCode : validCodes) {
            if (passwordEncoder.matches(normalizedCode, backupCode.getCodeHash())) {
                // Mark code as used
                backupCode.setUsed(true);
                backupCode.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(backupCode);

                long remainingCodes = backupCodeRepository.countValidCodesByUser(user);

                auditService.logAction(user, "BACKUP_CODE_VERIFICATION", true,
                        "Backup code used successfully. Remaining codes: " + remainingCodes, ipAddress);

                logger.info("Backup code verified for user: {}. Remaining codes: {}",
                        user.getUsername(), remainingCodes);

                if (remainingCodes <= 2) {
                    logger.warn("User {} has only {} backup codes remaining. Regeneration recommended.",
                            user.getUsername(), remainingCodes);
                }

                return true;
            }
        }

        auditService.logAction(user, "BACKUP_CODE_VERIFICATION", false,
                "Invalid backup code provided", ipAddress);

        throw new InvalidBackupCodeException("Invalid backup code. Please try again.");
    }

    @Transactional
    public List<String> regenerateBackupCodes(User user, String ipAddress) {
        List<String> newCodes = generateBackupCodes(user);
        auditService.logAction(user, "BACKUP_CODES_REGENERATED", true,
                "Backup codes regenerated", ipAddress);
        return newCodes;
    }

    public BackupCodeStatusResponse getBackupCodeStatus(User user) {
        List<BackupCode> allCodes = backupCodeRepository.findByUser(user);
        long totalCodes = allCodes.size();
        long usedCodes = allCodes.stream().filter(BackupCode::isUsed).count();
        long expiredCodes = allCodes.stream().filter(c -> !c.isUsed() && c.isExpired()).count();
        long remainingCodes = totalCodes - usedCodes - expiredCodes;

        return new BackupCodeStatusResponse(totalCodes, usedCodes, remainingCodes);
    }

    @Transactional
    public void invalidateAllBackupCodes(User user, String ipAddress) {
        backupCodeRepository.deleteAllByUser(user);
        auditService.logAction(user, "BACKUP_CODES_INVALIDATED", true,
                "All backup codes invalidated", ipAddress);
        logger.info("All backup codes invalidated for user: {}", user.getUsername());
    }
}

// ==================== Service: MfaService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.dto.MfaSetupResponse;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.MfaException;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.List;

@Service
public class MfaService {

    private static final Logger logger = LoggerFactory.getLogger(MfaService.class);

    @Value("${app.mfa.issuer:EnterpriseAuth}")
    private String issuer;

    private final UserRepository userRepository;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;
    private final AuditService auditService;
    private final RateLimitService rateLimitService;

    public MfaService(UserRepository userRepository,
                      TotpService totpService,
                      BackupCodeService backupCodeService,
                      AuditService auditService,
                      RateLimitService rateLimitService) {
        this.userRepository = userRepository;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
        this.auditService = auditService;
        this.rateLimitService = rateLimitService;
    }

    @Transactional
    public MfaSetupResponse initiateMfaSetup(String username) {
        User user = findUserByUsername(username);

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this account.");
        }

        String secret = totpService.generateSecret();
        user.setMfaSecret(secret);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);

        String qrCodeUri = totpService.getQrCodeUri(secret, username, issuer);

        auditService.logAction(user, "MFA_SETUP_INITIATED", true,
                "MFA setup initiated", null);

        MfaSetupResponse response = new MfaSetupResponse();
        response.setSecret(secret);
        response.setQrCodeUri(qrCodeUri);
        response.setMessage("Scan the QR code with your authenticator app, then verify with a TOTP code to complete setup.");

        return response;
    }

    @Transactional
    public MfaSetupResponse completeMfaSetup(String username, String totpCode, String ipAddress) {
        User user = findUserByUsername(username);

        if (user.isMfaEnabled()) {
            throw new MfaException("MFA is already enabled for this account.");
        }

        if (user.getMfaSecret() == null) {
            throw new MfaException("MFA setup has not been initiated. Please initiate setup first.");
        }

        boolean isValid = totpService.verifyCode(user.getMfaSecret(), totpCode);
        if (!isValid) {
            auditService.logAction(user, "MFA_SETUP_VERIFICATION", false,
                    "Invalid TOTP code during MFA setup", ipAddress);
            throw new MfaException("Invalid TOTP code. Please try again.");
        }

        user.setMfaEnabled(true);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);

        // Generate backup codes
        List<String> backupCodes = backupCodeService.generateBackupCodes(user);

        auditService.logAction(user, "MFA_ENABLED", true,
                "MFA enabled successfully with backup codes generated", ipAddress);

        logger.info("MFA enabled for user: {}", username);

        MfaSetupResponse response = new MfaSetupResponse();
        response.setBackupCodes(backupCodes);
        response.setMessage("MFA has been enabled successfully. Please save your backup codes in a secure location. " +
                "These codes can be used to access your account if you lose your MFA device.");

        return response;
    }

    @Transactional
    public boolean verifyMfaCode(String username, String totpCode, String ipAddress) {
        User user = findUserByUsername(username);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account.");
        }

        rateLimitService.checkMfaRateLimit(user);

        boolean isValid = totpService.verifyCode(user.getMfaSecret(), totpCode);

        auditService.logAction(user, "MFA_VERIFICATION", isValid,
                isValid ? "MFA verification successful" : "Invalid TOTP code", ipAddress);

        if (!isValid) {
            throw new MfaException("Invalid MFA code. Please try again.");
        }

        return true;
    }

    @Transactional
    public boolean verifyBackupCode(String username, String backupCode, String ipAddress) {
        User user = findUserByUsername(username);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account.");
        }

        return backupCodeService.verifyBackupCode(user, backupCode, ipAddress);
    }

    @Transactional
    public void disableMfa(String username, String totpCode, String ipAddress) {
        User user = findUserByUsername(username);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account.");
        }

        boolean isValid = totpService.verifyCode(user.getMfaSecret(), totpCode);
        if (!isValid) {
            auditService.logAction(user, "MFA_DISABLE_ATTEMPT", false,
                    "Invalid TOTP code during MFA disable", ipAddress);
            throw new MfaException("Invalid TOTP code. Cannot disable MFA.");
        }

        user.setMfaEnabled(false);
        user.setMfaSecret(null);
        user.setUpdatedAt(LocalDateTime.now());
        userRepository.save(user);

        backupCodeService.invalidateAllBackupCodes(user, ipAddress);

        auditService.logAction(user, "MFA_DISABLED", true,
                "MFA disabled successfully", ipAddress);

        logger.info("MFA disabled for user: {}", username);
    }

    @Transactional
    public List<String> regenerateBackupCodes(String username, String totpCode, String ipAddress) {
        User user = findUserByUsername(username);

        if (!user.isMfaEnabled()) {
            throw new MfaException("MFA is not enabled for this account.");
        }

        boolean isValid = totpService.verifyCode(user.getMfaSecret(), totpCode);
        if (!isValid) {
            auditService.logAction(user, "BACKUP_CODE_REGENERATION_ATTEMPT", false,
                    "Invalid TOTP code during backup code regeneration", ipAddress);
            throw new MfaException("Invalid TOTP code. Cannot regenerate backup codes.");
        }

        return backupCodeService.regenerateBackupCodes(user, ipAddress);
    }

    private User findUserByUsername(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));
    }
}

// ==================== Service: UserService ====================

package com.enterprise.auth.service;

import com.enterprise.auth.dto.RegisterRequest;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.exception.UserNotFoundException;
import com.enterprise.auth.repository.UserRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class UserService {

    private static final Logger logger = LoggerFactory.getLogger(UserService.class);

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final AuditService auditService;

    public UserService(UserRepository userRepository,
                       PasswordEncoder passwordEncoder,
                       AuditService auditService) {
        this.userRepository = userRepository;
        this.passwordEncoder = passwordEncoder;
        this.auditService = auditService;
    }

    @Transactional
    public User registerUser(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new IllegalArgumentException("Username already exists: " + request.getUsername());
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new IllegalArgumentException("Email already registered: " + request.getEmail());
        }

        User user = new User();
        user.setUsername(request.getUsername());
        user.setPassword(passwordEncoder.encode(request.getPassword()));
        user.setEmail(request.getEmail());

        User savedUser = userRepository.save(user);

        auditService.logAction(savedUser, "USER_REGISTERED", true,
                "User registered successfully", null);

        logger.info("User registered: {}", request.getUsername());
        return savedUser;
    }

    public boolean authenticateUser(String username, String password, String ipAddress) {
        User user = userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));

        boolean isValid = passwordEncoder.matches(password, user.getPassword());

        auditService.logAction(user, "LOGIN_ATTEMPT", isValid,
                isValid ? "Password verification successful" : "Invalid password", ipAddress);

        return isValid;
    }

    public User getUserByUsername(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new UserNotFoundException("User not found: " + username));
    }
}

// ==================== Controller: AuthController ====================

package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.service.MfaService;
import com.enterprise.auth.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final UserService userService;
    private final MfaService mfaService;

    public AuthController(UserService userService, MfaService mfaService) {
        this.userService = userService;
        this.mfaService = mfaService;
    }

    @PostMapping("/register")
    public ResponseEntity<ApiResponse> register(@Valid @RequestBody RegisterRequest request) {
        User user = userService.registerUser(request);
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(new ApiResponse(true, "User registered successfully. Username: " + user.getUsername()));
    }

    @PostMapping("/login")
    public ResponseEntity<ApiResponse> login(@Valid @RequestBody LoginRequest request, HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        boolean authenticated = userService.authenticateUser(request.getUsername(), request.getPassword(), ipAddress);

        if (!authenticated) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED)
                    .body(new ApiResponse(false, "Invalid credentials."));
        }

        User user = userService.getUserByUsername(request.getUsername());

        if (user.isMfaEnabled()) {
            return ResponseEntity.ok(new ApiResponse(true, "Password verified. MFA verification required.", "MFA_REQUIRED"));
        }

        return ResponseEntity.ok(new ApiResponse(true, "Login successful."));
    }

    @PostMapping("/verify-mfa")
    public ResponseEntity<ApiResponse> verifyMfa(@Valid @RequestBody MfaVerificationRequest request,
                                                  HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        mfaService.verifyMfaCode(request.getUsername(), request.getTotpCode(), ipAddress);
        return ResponseEntity.ok(new ApiResponse(true, "MFA verification successful. Login complete."));
    }

    @PostMapping("/verify-backup-code")
    public ResponseEntity<ApiResponse> verifyBackupCode(@Valid @RequestBody BackupCodeVerificationRequest request,
                                                         HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        mfaService.verifyBackupCode(request.getUsername(), request.getBackupCode(), ipAddress);
        return ResponseEntity.ok(new ApiResponse(true,
                "Backup code verified successfully. Login complete. Please consider regenerating your backup codes."));
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }
}

// ==================== Controller: MfaController ====================

package com.enterprise.auth.controller;

import com.enterprise.auth.dto.*;
import com.enterprise.auth.entity.User;
import com.enterprise.auth.service.BackupCodeService;
import com.enterprise.auth.service.MfaService;
import com.enterprise.auth.service.UserService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/mfa")
public class MfaController {

    private final MfaService mfaService;
    private final BackupCodeService backupCodeService;
    private final UserService userService;

    public MfaController(MfaService mfaService, BackupCodeService backupCodeService, UserService userService) {
        this.mfaService = mfaService;
        this.backupCodeService = backupCodeService;
        this.userService = userService;
    }

    @PostMapping("/setup/initiate")
    public ResponseEntity<ApiResponse> initiateMfaSetup(@RequestParam String username) {
        MfaSetupResponse setupResponse = mfaService.initiateMfaSetup(username);
        return ResponseEntity.ok(new ApiResponse(true, setupResponse.getMessage(), setupResponse));
    }

    @PostMapping("/setup/complete")
    public ResponseEntity<ApiResponse> completeMfaSetup(@Valid @RequestBody EnableMfaRequest request,
                                                         HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        MfaSetupResponse response = mfaService.completeMfaSetup(request.getUsername(), request.getTotpCode(), ipAddress);
        return ResponseEntity.ok(new ApiResponse(true, response.getMessage(), response));
    }

    @PostMapping("/disable")
    public ResponseEntity<ApiResponse> disableMfa(@Valid @RequestBody MfaVerificationRequest request,
                                                   HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        mfaService.disableMfa(request.getUsername(), request.getTotpCode(), ipAddress);
        return ResponseEntity.ok(new ApiResponse(true, "MFA has been disabled successfully."));
    }

    @PostMapping("/backup-codes/regenerate")
    public ResponseEntity<ApiResponse> regenerateBackupCodes(@Valid @RequestBody MfaVerificationRequest request,
                                                              HttpServletRequest httpRequest) {
        String ipAddress = getClientIpAddress(httpRequest);
        List<String> newCodes = mfaService.regenerateBackupCodes(request.getUsername(), request.getTotpCode(), ipAddress);
        return ResponseEntity.ok(new ApiResponse(true,
                "New backup codes generated. Previous codes have been invalidated. Please save these codes securely.",
                newCodes));
    }

    @GetMapping("/backup-codes/status")
    public ResponseEntity<ApiResponse> getBackupCodeStatus(@RequestParam String username) {
        User user = userService.getUserByUsername(username);
        BackupCodeStatusResponse status = backupCodeService.getBackupCodeStatus(user);
        return ResponseEntity.ok(new ApiResponse(true, "Backup code status retrieved.", status));
    }

    @GetMapping("/status")
    public ResponseEntity<ApiResponse> getMfaStatus(@RequestParam String username) {
        User user = userService.getUserByUsername(username);
        return ResponseEntity.ok(new ApiResponse(true, "MFA status retrieved.",
                new MfaStatusDto(user.isMfaEnabled())));
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    static class MfaStatusDto {
        private boolean mfaEnabled;

        public MfaStatusDto(boolean mfaEnabled) {
            this.mfaEnabled = mfaEnabled;
        }

        public boolean isMfaEnabled() { return mfaEnabled; }
        public void setMfaEnabled(boolean mfaEnabled) { this.mfaEnabled = mfaEnabled; }
    }
}

// ==================== Security Configuration ====================

package com.enterprise.auth.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.annotation.web.configurers.HeadersConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    @Bean
    public PasswordEncoder passwordEncoder() {
        return new BCryptPasswordEncoder(12);
    }

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(AbstractHttpConfigurer::disable)
                .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
                .headers(headers -> headers.frameOptions(HeadersConfigurer.FrameOptionsConfig::sameOrigin))
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/auth/**").permitAll()
                        .requestMatchers("/api/mfa/**").permitAll()
                        .requestMatchers("/h2-console/**").permitAll()
                        .anyRequest().authenticated()
                );

        return http.build();
    }
}

